// Logo component that renders the appropriate SVG
function IntegrationLogo({ name }: { name: string }) {
  const logoMap: Record<string, React.ReactNode> = {
    "Gmail": <GmailLogo />,
    "Google Sheets": <GoogleSheetsLogo />,
    "Google Drive": <GoogleDriveLogo />,
    "Google Calendar": <GoogleCalendarLogo />,
    "Slack": <SlackLogo />,
    "GitHub": <GitHubLogo />,
    "Notion": <NotionLogo />,
    "Stripe": <StripeLogo />,
    "Salesforce": <SalesforceLogo />,
    "HubSpot": <HubSpotLogo />,
    "Jira": <JiraLogo />,
    "Asana": <AsanaLogo />,
    "Trello": <TrelloLogo />,
    "Discord": <DiscordLogo />,
    "Zoom": <ZoomLogo />,
    "Microsoft Teams": <TeamsLogo />,
    "Airtable": <AirtableLogo />,
    "Dropbox": <DropboxLogo />,
    "OneDrive": <OneDriveLogo />,
    "Box": <BoxLogo />,
    "Figma": <FigmaLogo />,
    "Linear": <LinearLogo />,
    "Intercom": <IntercomLogo />,
    "Zendesk": <ZendeskLogo />,
    "Mailchimp": <MailchimpLogo />,
    "SendGrid": <SendGridLogo />,
    "Twilio": <TwilioLogo />,
    "AWS": <AWSLogo />,
    "Vercel": <VercelLogo />,
    "Supabase": <SupabaseLogo />,
    "MongoDB": <MongoDBLogo />,
    "PostgreSQL": <PostgreSQLLogo />,
  }

  return logoMap[name] || null
}

export function IntegrationLogosCarousel() {
  const containerRef = useRef<HTMLDivElement>(null)
  const row1Ref = useRef<HTMLDivElement>(null)
  const row2Ref = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (!row1Ref.current || !row2Ref.current) return

    // Animate row 1 (left to right)
    gsap.to(row1Ref.current, {
      xPercent: -50,
      duration: 40,
      ease: "none",
      repeat: -1,
    })

    // Animate row 2 (right to left)
    gsap.fromTo(
      row2Ref.current,
      { xPercent: -50 },
      {
        xPercent: 0,
        duration: 45,
        ease: "none",
        repeat: -1,
      }
    )
  }, [])

  return (
    <div ref={containerRef} className="w-full overflow-hidden py-8 space-y-6">
      {/* Powered by badge */}
      <div className="flex items-center justify-center gap-2 mb-4">
        <span className="font-mono text-[10px] uppercase tracking-[0.3em] text-muted-foreground">
          Powered by Composio
        </span>
        <span className="text-accent">•</span>
        <span className="font-mono text-[10px] uppercase tracking-[0.3em] text-accent">
          67+ Integrations
        </span>
        <span className="text-accent">•</span>
        <span className="font-mono text-[10px] uppercase tracking-[0.3em] text-muted-foreground">
          SOC 2 Compliant
        </span>
      </div>

      {/* Row 1 - scrolling left */}
      <div className="relative">
        <div className="absolute left-0 top-0 bottom-0 w-24 bg-gradient-to-r from-background to-transparent z-10" />
        <div className="absolute right-0 top-0 bottom-0 w-24 bg-gradient-to-l from-background to-transparent z-10" />
        <div ref={row1Ref} className="flex gap-8 w-fit">
          {[...integrations, ...integrations].map((integration, index) => (
            <div
              key={`row1-${index}`}
              className="group flex items-center gap-3 px-5 py-3 border border-border/30 hover:border-accent/50 transition-all duration-300 bg-card/50 backdrop-blur-sm flex-shrink-0"
            >
              <div className="w-6 h-6 flex-shrink-0 opacity-70 group-hover:opacity-100 transition-opacity">
                <IntegrationLogo name={integration.name} />
              </div>
              <span className="font-mono text-xs text-muted-foreground group-hover:text-foreground transition-colors whitespace-nowrap">
                {integration.name}
              </span>
            </div>
          ))}
        </div>
      </div>

      {/* Row 2 - scrolling right */}
      <div className="relative">
        <div className="absolute left-0 top-0 bottom-0 w-24 bg-gradient-to-r from-background to-transparent z-10" />
        <div className="absolute right-0 top-0 bottom-0 w-24 bg-gradient-to-l from-background to-transparent z-10" />
        <div ref={row2Ref} className="flex gap-8 w-fit">
          {[...integrationsRow2, ...integrationsRow2].map((integration, index) => (
            <div
              key={`row2-${index}`}
              className="group flex items-center gap-3 px-5 py-3 border border-border/30 hover:border-accent/50 transition-all duration-300 bg-card/50 backdrop-blur-sm flex-shrink-0"
            >
              <div className="w-6 h-6 flex-shrink-0 opacity-70 group-hover:opacity-100 transition-opacity">
                <IntegrationLogo name={integration.name} />
              </div>
              <span className="font-mono text-xs text-muted-foreground group-hover:text-foreground transition-colors whitespace-nowrap">
                {integration.name}
              </span>
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}
